import React, { useMemo, useState } from 'react';
import { Mail, Phone, ShieldCheck, UserPlus } from 'lucide-react';

export default function CustomerRegisterCard({ onSubmit, isLoading }) {
  const [form, setForm] = useState({
    name: '',
    email: '',
    phone: '',
    password: '',
    gender: 'male',
  });
  const [otpInput, setOtpInput] = useState('');
  const [otpState, setOtpState] = useState({ code: '', sent: false, verified: false, message: '', isError: false });

  const googleAuthUrl = useMemo(() => {
    const base = process.env.REACT_APP_API_URL || 'http://localhost:5000/api';
    return process.env.REACT_APP_GOOGLE_OAUTH_URL || `${base}/auth/customers/google`;
  }, []);

  const handleChange = (e) => setForm((prev) => ({ ...prev, [e.target.name]: e.target.value }));

  const handleSubmit = (e) => {
    e.preventDefault();
    if (!otpState.verified) {
      alert('Please verify the OTP sent to your email before creating an account.');
      return;
    }
    onSubmit({ ...form, otp: otpInput });
  };

  const handleSendOtp = () => {
    if (!form.email || !form.phone) {
      setOtpState({
        code: '',
        sent: false,
        verified: false,
        message: 'Add your email and mobile number before requesting an OTP.',
        isError: true,
      });
      return;
    }
    const code = Math.floor(100000 + Math.random() * 900000).toString();
    setOtpState({
      code,
      sent: true,
      verified: false,
      message: `OTP sent to ${form.email}. (Demo OTP: ${code})`,
      isError: false,
    });
    setOtpInput('');
  };

  const handleVerifyOtp = () => {
    if (!otpState.sent) {
      setOtpState((prev) => ({ ...prev, message: 'Please send OTP first.', isError: true }));
      return;
    }
    const verified = otpInput === otpState.code;
    setOtpState((prev) => ({
      ...prev,
      verified,
      message: verified ? 'OTP verified successfully.' : 'OTP did not match. Try again.',
      isError: !verified,
    }));
  };

  const handleGoogleAuth = () => {
    window.location.href = googleAuthUrl;
  };

  return (
    <div className="card shadow border-0">
      <div className="card-body p-4">
        <div className="text-center mb-4">
          <UserPlus size={32} className="text-danger mb-2" />
          <h3 className="h5">Create your Dhakkhana ID</h3>
          <p className="text-muted small">One profile for bookings, tracking, and citizen services.</p>
        </div>
        <form onSubmit={handleSubmit} className="row g-3">
          <div className="col-md-6">
            <label className="form-label">Full Name</label>
            <input className="form-control" name="name" value={form.name} onChange={handleChange} required />
          </div>
          <div className="col-md-6">
            <label className="form-label">Gender</label>
            <select className="form-select" name="gender" value={form.gender} onChange={handleChange} required>
              <option value="male">Male</option>
              <option value="female">Female</option>
              <option value="prefer_not_say">Prefer not to say</option>
            </select>
          </div>
          <div className="col-md-6">
            <label className="form-label">Mobile number</label>
            <div className="input-group">
              <span className="input-group-text">
                <Phone size={16} />
              </span>
              <input
                className="form-control"
                name="phone"
                value={form.phone}
                onChange={handleChange}
                placeholder="+91 98765 43210"
                required
              />
            </div>
          </div>
          <div className="col-md-6">
            <label className="form-label">Email</label>
            <div className="input-group">
              <span className="input-group-text">
                <Mail size={16} />
              </span>
              <input
                type="email"
                className="form-control"
                name="email"
                value={form.email}
                onChange={handleChange}
                required
              />
            </div>
          </div>
          <div className="col-12">
            <label className="form-label">Password</label>
            <input
              type="password"
              className="form-control"
              name="password"
              value={form.password}
              onChange={handleChange}
              minLength={6}
              required
            />
          </div>
          <div className="col-md-7">
            <label className="form-label">Email OTP</label>
            <input
              className="form-control"
              placeholder="Enter 6-digit code"
              value={otpInput}
              onChange={(e) => setOtpInput(e.target.value)}
              maxLength={6}
            />
          </div>
          <div className="col-md-5 d-flex align-items-end gap-2">
            <button type="button" className="btn btn-outline-secondary w-100" onClick={handleSendOtp}>
              Send OTP
            </button>
            <button type="button" className="btn btn-outline-success w-100" onClick={handleVerifyOtp}>
              Verify
            </button>
          </div>
          {otpState.message && (
            <div className={`col-12 small ${otpState.isError ? 'text-danger' : 'text-success'}`}>{otpState.message}</div>
          )}
          <div className="col-12 d-flex align-items-center gap-2">
            <ShieldCheck size={20} className="text-success" />
            <p className="small text-muted mb-0">
              We use OTP verification to keep your Dhakkhana account safe and compliant with DIGI-locker norms.
            </p>
          </div>
          <div className="col-12">
            <button className="btn btn-danger w-100" disabled={isLoading || !otpState.verified}>
              {isLoading ? 'Creating...' : 'Create Account'}
            </button>
          </div>
          <div className="col-12">
            <button type="button" className="btn btn-outline-secondary w-100" onClick={handleGoogleAuth}>
              Sign up with Google
            </button>
          </div>
        </form>
      </div>
    </div>
  );
}
